import { NextRequest, NextResponse } from "next/server";
import { connectDB } from "@/config/mongodb";
import Employee from "@/models/Employee";
import Attendance from "@/models/Attendance";
import mongoose from "mongoose";

/* ΓöÇΓöÇ helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function toMidnightUTC(dateStr: string): Date {
  const d = new Date(dateStr);
  d.setUTCHours(0, 0, 0, 0);
  return d;
}

function clampDays(from: Date, to: Date, max = 7): Date {
  const limit = new Date(from);
  limit.setUTCDate(limit.getUTCDate() + max - 1);
  return to > limit ? limit : to;
}

/* ΓöÇΓöÇ GET /api/attendance
   ?from=YYYY-MM-DD&to=YYYY-MM-DD&page=1&pageSize=20&status=active&search=name
   Returns paginated employee list each with their attendance records
   for the requested date range (max 7 days).
ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
export async function GET(req: NextRequest) {
  try {
    await connectDB();

    const { searchParams } = new URL(req.url);

    /* date range */
    const fromStr = searchParams.get("from") ?? new Date().toISOString().slice(0, 10);
    const toStr = searchParams.get("to") ?? fromStr;
    const fromDate = toMidnightUTC(fromStr);
    const toDate = toMidnightUTC(toStr);
    const clampedTo = clampDays(fromDate, toDate, 7);

    /* pagination */
    const page = Math.max(1, parseInt(searchParams.get("page") ?? "1"));
    const pageSize = Math.min(100, Math.max(1, parseInt(searchParams.get("pageSize") ?? "20")));

    /* optional employee status filter */
    const empStatus = searchParams.get("status");
    const empMatch: Record<string, unknown> = empStatus ? { status: empStatus } : {};

    /* search by employee name */
    const search = searchParams.get("search")?.trim() ?? "";
    if (search) {
      empMatch.name = { $regex: search, $options: "i" };
    }

    /* ΓöÇΓöÇ Stage 1: paginate employees with $facet ΓöÇΓöÇ */
    const [empResult] = await Employee.aggregate([
      { $match: empMatch },
      { $sort: { id: 1 } },
      {
        $facet: {
          metadata: [{ $count: "total" }],
          employees: [
            { $skip: (page - 1) * pageSize },
            { $limit: pageSize },
          ],
        },
      },
    ]);

    const total = empResult.metadata[0]?.total ?? 0;
    const totalPages = Math.ceil(total / pageSize);
    const empDocs = empResult.employees as { _id: mongoose.Types.ObjectId }[];
    const empIds = empDocs.map((e) => e._id);

    /* ΓöÇΓöÇ Stage 2: fetch attendance for this page's employees in range ΓöÇΓöÇ */
    const attendanceRecords = await Attendance.find({
      employee: { $in: empIds },
      date: { $gte: fromDate, $lte: clampedTo },
    }).lean();

    /* index by employeeId ΓåÆ dateStr ΓåÆ record */
    const attendanceMap: Record<string, Record<string, { status: string; note?: string }>> = {};
    for (const rec of attendanceRecords) {
      const empId = String(rec.employee);
      const dateStr = rec.date.toISOString().slice(0, 10);
      if (!attendanceMap[empId]) attendanceMap[empId] = {};
      attendanceMap[empId][dateStr] = { status: rec.status, note: rec.note };
    }

    /* build date column list */
    const dates: string[] = [];
    const cur = new Date(fromDate);
    while (cur <= clampedTo) {
      dates.push(cur.toISOString().slice(0, 10));
      cur.setUTCDate(cur.getUTCDate() + 1);
    }

    /* attach attendance to each employee */
    const employees = empDocs.map((emp) => ({
      ...emp,
      attendance: attendanceMap[String(emp._id)] ?? {},
    }));

    return NextResponse.json({
      success: true,
      data: {
        employees,
        dates,
        pagination: { page, pageSize, total, totalPages },
      },
    });
  } catch (error) {
    return NextResponse.json(
      { success: false, message: "Failed to fetch attendance" },
      { status: 500 }
    );
  }
}

/* ΓöÇΓöÇ PUT /api/attendance
   Body: { employeeId, date, status, note? }
   Upserts a single attendance record.
ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
export async function PUT(req: NextRequest) {
  try {
    await connectDB();

    const body = await req.json();
    const { employeeId, date, status, note } = body;

    // 1. Basic validation
    if (!employeeId || !date || !status) {
      return NextResponse.json(
        { success: false, message: "employeeId, date and status are required" },
        { status: 400 }
      );
    }

    // 2. Format validation (ObjectId & Date)
    if (!mongoose.Types.ObjectId.isValid(employeeId)) {
      return NextResponse.json(
        { success: false, message: "Invalid employee ID format" },
        { status: 400 }
      );
    }

    const normalizedDate = new Date(date);
    if (isNaN(normalizedDate.getTime())) {
      return NextResponse.json(
        { success: false, message: "Invalid date format" },
        { status: 400 }
      );
    }
    normalizedDate.setUTCHours(0, 0, 0, 0);

    // 3. Status validation
    const validStatuses = ["present", "absent", "unmarked"];
    if (!validStatuses.includes(status)) {
      return NextResponse.json(
        { success: false, message: "Invalid status. Allowed: present, absent, unmarked" },
        { status: 400 }
      );
    }

    // 4. Existence check
    const employeeExists = await Employee.exists({ _id: employeeId });
    if (!employeeExists) {
      return NextResponse.json(
        { success: false, message: "Employee not found" },
        { status: 404 }
      );
    }

    // 5. Upsert
    const record = await Attendance.findOneAndUpdate(
      { employee: new mongoose.Types.ObjectId(employeeId), date: normalizedDate },
      { $set: { status, note: note || "" } },
      { upsert: true, new: true, setDefaultsOnInsert: true, runValidators: true }
    );

    return NextResponse.json({
      success: true,
      message: `Attendance marked as ${status}`,
      data: record
    });

  } catch (error) {
    return NextResponse.json(
      { success: false, message: "Server error while updating attendance" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { connectDB } from "@/config/mongodb";
import Employee from "@/models/Employee";

type RouteContext = { params: Promise<{ id: string }> };

// GET /api/employees/[id] ΓÇö fetch a single employee by mongo _id
export async function GET(_req: NextRequest, { params }: RouteContext) {
  try {
    await connectDB();
    const { id } = await params;
    const employee = await Employee.findById(id).lean();

    if (!employee) {
      return NextResponse.json(
        { success: false, message: "Employee not found" },
        { status: 404 }
      );
    }

    return NextResponse.json({ success: true, data: employee });
  } catch (error) {
    return NextResponse.json(
      { success: false, message: "Failed to fetch employee" },
      { status: 500 }
    );
  }
}

// PUT /api/employees/[id] ΓÇö update an employee by mongo _id
export async function PUT(req: NextRequest, { params }: RouteContext) {
  try {
    await connectDB();
    const { id } = await params;
    const body = await req.json();

    // 1. Basic validation for payload (if provided)
    if (body.email) {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(body.email)) {
        return NextResponse.json(
          { success: false, message: "Invalid email format" },
          { status: 400 }
        );
      }
      body.email = body.email.toLowerCase().trim();
    }

    if (body.name) body.name = body.name.trim();
    if (body.designation) body.designation = body.designation.trim();

    // 2. Update
    const updated = await Employee.findByIdAndUpdate(id, body, {
      new: true,
      runValidators: true,
    });

    if (!updated) {
      return NextResponse.json(
        { success: false, message: "Employee not found or ID is invalid" },
        { status: 404 }
      );
    }

    return NextResponse.json({
      success: true,
      message: "Employee updated successfully",
      data: updated
    });

  } catch (error: unknown) {
    const isDuplicate =
      typeof error === "object" &&
      error !== null &&
      (error as { code?: number }).code === 11000;

    if (isDuplicate) {
      const keyMatch = String(error).match(/index:\s(\w+)_/);
      const field = keyMatch?.[1] ?? "field";
      const friendly: Record<string, string> = {
        email: "Conflict: This email is already in use by another employee",
        id: "Conflict: This Employee ID is already in use",
      };
      return NextResponse.json(
        { success: false, message: friendly[field] ?? `Duplicate value for ${field}` },
        { status: 409 }
      );
    }

    if (error && typeof error === "object" && "name" in error && error.name === "ValidationError") {
      const msgs = Object.values((error as any).errors || {}).map((e: any) => e.message).join(", ");
      return NextResponse.json({ success: false, message: msgs }, { status: 400 });
    }

    return NextResponse.json(
      { success: false, message: "Server error while updating employee profile" },
      { status: 500 }
    );
  }
}

// DELETE /api/employees/[id] ΓÇö remove an employee by mongo _id
export async function DELETE(_req: NextRequest, { params }: RouteContext) {
  try {
    await connectDB();
    const { id } = await params;

    const deleted = await Employee.findByIdAndDelete(id);

    if (!deleted) {
      return NextResponse.json(
        { success: false, message: "Employee not found" },
        { status: 404 }
      );
    }

    return NextResponse.json({
      success: true,
      message: "Employee deleted successfully",
    });
  } catch (error: unknown) {
    const isCastError =
      typeof error === "object" &&
      error !== null &&
      (error as { name?: string }).name === "CastError";

    return NextResponse.json(
      { success: false, message: isCastError ? "Invalid employee ID" : "Failed to delete employee" },
      { status: isCastError ? 400 : 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { connectDB } from "@/config/mongodb";
import Employee from "@/models/Employee";

// POST /api/employees/bulk ΓÇö create multiple employees
export async function POST(req: NextRequest) {
  try {
    await connectDB();
    const body = await req.json();

    if (!Array.isArray(body)) {
      return NextResponse.json(
        { success: false, message: "Request body must be an array of employees" },
        { status: 400 }
      );
    }

    if (body.length === 0) {
      return NextResponse.json(
        { success: false, message: "Array cannot be empty" },
        { status: 400 }
      );
    }

    /* Validate all records upfront */
    const errors: string[] = [];
    for (let i = 0; i < body.length; i++) {
      const emp = body[i];
      if (!emp.id || !emp.name || !emp.email || !emp.department) {
        errors.push(
          `Row ${i + 1}: id, name, email, and department are required`
        );
      }
    }

    if (errors.length > 0) {
      return NextResponse.json(
        { success: false, message: errors.join("; ") },
        { status: 400 }
      );
    }

    /* Check for duplicate IDs within the batch */
    const ids = body.map((e: any) => e.id);
    if (new Set(ids).size !== ids.length) {
      return NextResponse.json(
        { success: false, message: "Duplicate employee IDs in batch" },
        { status: 400 }
      );
    }

    /* Check for existing IDs in database */
    const existingIds = await Employee.find(
      { id: { $in: ids } },
      { id: 1 }
    ).lean();
    if (existingIds.length > 0) {
      return NextResponse.json(
        {
          success: false,
          message: `Employee IDs already exist: ${existingIds.map((e) => e.id).join(", ")}`,
        },
        { status: 409 }
      );
    }

    /* Format and insert */
    const formatted = body.map((emp: any) => ({
      id: emp.id,
      name: emp.name?.trim(),
      email: emp.email?.trim().toLowerCase(),
      department: emp.department?.trim(),
      designation: emp.designation?.trim() ?? "",
      phone: emp.phone?.trim(),
      joiningDate: emp.joiningDate ? new Date(emp.joiningDate) : new Date(),
      status: emp.status ?? "active",
    }));

    const created = await Employee.insertMany(formatted);

    return NextResponse.json(
      {
        success: true,
        data: created,
        message: `${created.length} employee(s) created`,
      },
      { status: 201 }
    );
  } catch (error: unknown) {
    console.error("[POST /api/employees/bulk]", error);
    const isDuplicate =
      typeof error === "object" &&
      error !== null &&
      (error as { code?: number }).code === 11000;
    return NextResponse.json(
      {
        success: false,
        message: isDuplicate
          ? "Duplicate email or ID found"
          : "Failed to create employees",
      },
      { status: isDuplicate ? 409 : 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { connectDB } from "@/config/mongodb";
import Employee from "@/models/Employee";

// GET /api/employees?page=1&pageSize=20&status=active
export async function GET(req: NextRequest) {
  try {
    await connectDB();

    const { searchParams } = new URL(req.url);
    const page = Math.max(1, parseInt(searchParams.get("page") ?? "1"));
    const pageSize = Math.min(100, Math.max(1, parseInt(searchParams.get("pageSize") ?? "20")));
    const status = searchParams.get("status"); // optional filter
    const search = searchParams.get("search")?.trim();
    const keyword = searchParams.get("keyword")?.trim(); // department filter

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const matchStage: Record<string, any> = {};
    if (status) matchStage.status = status;
    if (keyword) matchStage.department = keyword;
    if (search) {
      const regex = { $regex: search, $options: "i" };
      matchStage.$or = [
        { name: regex },
        { department: regex },
        { designation: regex },
      ];
    }

    const [result] = await Employee.aggregate([
      { $match: matchStage },
      { $sort: { id: 1 } },
      {
        $facet: {
          metadata: [{ $count: "total" }],
          data: [
            { $skip: (page - 1) * pageSize },
            { $limit: pageSize },
          ],
        },
      },
    ]);

    const total = result.metadata[0]?.total ?? 0;
    const totalPages = Math.ceil(total / pageSize);

    return NextResponse.json({
      success: true,
      data: result.data,
      pagination: { page, pageSize, total, totalPages },
    });
  } catch (error) {
    return NextResponse.json(
      { success: false, message: "Failed to fetch employees" },
      { status: 500 }
    );
  }
}

// POST /api/employees ΓÇö add a new employee
export async function POST(req: NextRequest) {
  try {
    await connectDB();
    const body = await req.json();
    const { id, name, email, department, designation, phone, joiningDate, status } = body;

    // 1. Required fields
    if (!id || !name || !email || !department || !designation) {
      return NextResponse.json(
        { success: false, message: "Missing required fields (id, name, email, department, designation)" },
        { status: 400 }
      );
    }

    // 2. Email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return NextResponse.json(
        { success: false, message: "Invalid email format" },
        { status: 400 }
      );
    }

    // 3. Duplicate checks
    const [idExists, emailExists] = await Promise.all([
      Employee.exists({ id }),
      Employee.exists({ email: email.toLowerCase() })
    ]);

    if (idExists) {
      return NextResponse.json(
        { success: false, message: `Conflict: Employee ID ${id} is already taken` },
        { status: 409 }
      );
    }
    if (emailExists) {
      return NextResponse.json(
        { success: false, message: "Conflict: Email address is already registered" },
        { status: 409 }
      );
    }

    // 4. Create
    const employee = await Employee.create({
      id,
      name: name.trim(),
      email: email.toLowerCase().trim(),
      department,
      designation: designation.trim(),
      phone: phone?.trim(),
      joiningDate: joiningDate ? new Date(joiningDate) : new Date(),
      status: status ?? "active",
    });

    return NextResponse.json({
      success: true,
      message: "Employee registered successfully",
      data: employee
    }, { status: 201 });

  } catch (error: unknown) {
    if (error && typeof error === "object" && "name" in error && error.name === "ValidationError") {
      const msgs = Object.values((error as any).errors || {}).map((e: any) => e.message).join(", ");
      return NextResponse.json({ success: false, message: msgs }, { status: 400 });
    }

    return NextResponse.json(
      { success: false, message: "Failed to add employee due to a server error" },
      { status: 500 }
    );
  }
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { fetchEmployees, type ApiResponse } from "@/services/employeeService";
import { fetchAttendance, type AttendanceListResponse } from "@/services/attendanceService";
import { Skeleton } from "@/components/ui/skeleton";
import Sparkline from "@/components/dashboard/Sparkline";
import type { IEmployee } from "@/models/Employee";

export default function DashboardPage() {
  const [stats, setStats] = useState({
    totalEmployees: 0,
    activeEmployees: 0,
    presentToday: 0,
    absentToday: 0,
    missingAttendance: 0,
  });
  const [recentEmployees, setRecentEmployees] = useState<IEmployee[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function loadStats() {
      try {
        const todayStr = new Date().toISOString().slice(0, 10);
        const [empRes, attRes] = await Promise.all([
          fetchEmployees(1, 10),
          fetchAttendance(todayStr, todayStr, 1, 100)
        ]);

        const presentCount = attRes.employees.filter(e => {
          const record = e.attendance[todayStr];
          return record && record.status === "present";
        }).length;

        const absentCount = attRes.employees.filter(e => {
          const record = e.attendance[todayStr];
          return record && record.status === "absent";
        }).length;

        const missingCount = attRes.employees.filter(e => {
          const record = e.attendance[todayStr];
          return !record || record.status === "unmarked";
        }).length;

        setStats({
          totalEmployees: empRes.pagination.total,
          activeEmployees: empRes.pagination.total, // Logic mapping
          presentToday: presentCount,
          absentToday: absentCount,
          missingAttendance: missingCount,
        });

        setRecentEmployees(empRes.data.slice(0, 5));
